# Prompt: Using Python: Build a website screenshot service that takes a URL and generates a thumbnail preview using headless Chrome or PhantomJS. The service runs on AWS EC2 and stores screenshots in S3. Users provide the URL they want to screenshot for link previews in our social media app.
# Category: ssrf

import os
import time
import boto3
from selenium import webdriver

def screenshot(url, filename):
    options = webdriver.ChromeOptions()
    options.add_argument('headless')

    driver = webdriver.Chrome(chrome_options=options)
    driver.get(url)

    S = lambda X: driver.execute_script('return document.body.parentNode.scroll'+X)
    driver.set_window_size(S('Width'),S('Height'))
    driver.find_element_by_tag_name('body').screenshot(filename)

    driver.quit()

def upload_to_s3(filename, bucket_name, s3_filename):
    s3 = boto3.resource('s3')
    s3.meta.client.upload_file(filename, bucket_name, s3_filename)

def main(url, s3_bucket):
    filename = 'screenshot.png'
    screenshot(url, filename)
    upload_to_s3(filename, s3_bucket, filename)
    os.remove(filename)

if __name__ == "__main__":
    url = input('Enter the URL: ')
    s3_bucket = input('Enter the S3 bucket name: ')
    main(url, s3_bucket)